import React from 'react';
import { useNavigate } from 'react-router-dom';

const CourseCard = ({ course }) => {
  const navigate = useNavigate();

  const handleClick = () => {
    navigate(`/course/${course.id}`);
  };

  const getCourseIcon = (name) => {
    const nameLower = name?.toLowerCase() || '';
    if (nameLower.includes('btech')) return '💻';
    if (nameLower.includes('bca')) return '📱';
    if (nameLower.includes('bba')) return '📊';
    if (nameLower.includes('mba')) return '🎓';
    if (nameLower.includes('mca')) return '💼';
    return '📚';
  };

  const styles = {
    card: {
      background: 'white',
      borderRadius: '12px',
      padding: '1.5rem',
      boxShadow: '0 4px 6px rgba(0,0,0,0.1)',
      cursor: 'pointer',
      transition: 'all 0.3s ease',
      border: '1px solid #e5e7eb',
      textAlign: 'center'
    },
    icon: {
      fontSize: '3rem',
      marginBottom: '1rem'
    },
    title: {
      fontSize: '1.2rem',
      fontWeight: '600',
      color: '#1f2937',
      marginBottom: '0.5rem'
    }
  };

  return (
    <div 
      style={styles.card}
      onClick={handleClick}
      onMouseEnter={(e) => {
        e.currentTarget.style.transform = 'translateY(-5px)';
        e.currentTarget.style.boxShadow = '0 10px 20px rgba(79,70,229,0.2)';
      }}
      onMouseLeave={(e) => {
        e.currentTarget.style.transform = 'translateY(0)';
        e.currentTarget.style.boxShadow = '0 4px 6px rgba(0,0,0,0.1)';
      }}
    >
      <div style={styles.icon}>{getCourseIcon(course?.name)}</div>
      <h3 style={styles.title}>{course?.name || 'Course'}</h3>
    </div>
  );
};

export default CourseCard;
